namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough into a circle.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute.\n5. Bake for 10-12 minutes.\n6. Top with fresh basil and olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti in salted water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat, stir in egg mixture.\n6. Serve immediately with extra pecorino.", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Tomato sauce, Heavy cream, Onion, Garlic, Ginger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and simmer.\n5. Stir in cream and garam masala.\n6. Add chicken pieces and simmer 10 minutes.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 4, Title = "Vegetable Biryani", Category = "Indian", Ingredients = "Basmati rice, Mixed vegetables, Onions, Yogurt, Biryani spices, Saffron, Ghee, Mint", Steps = "1. Soak rice for 30 minutes.\n2. Fry onions until golden.\n3. Cook vegetables with spices.\n4. Layer rice and vegetable mixture.\n5. Add saffron milk and ghee.\n6. Cover and cook on low heat for 20 minutes.", AverageRating = 4.3, RatingCount = 8 },
        new Recipe { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheddar cheese, Sour cream, Taco seasoning", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water.\n3. Simmer until sauce thickens.\n4. Warm taco shells.\n5. Fill with beef and toppings.\n6. Serve with sour cream.", AverageRating = 4.2, RatingCount = 10 },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime juice, Cilantro, Red onion, Jalapeño, Tomato, Salt", Steps = "1. Halve and pit avocados.\n2. Mash to desired consistency.\n3. Dice onion, tomato, and jalapeño.\n4. Mix all ingredients together.\n5. Add lime juice and salt.\n6. Serve immediately with chips.", AverageRating = 4.7, RatingCount = 18 },
        new Recipe { Id = 7, Title = "Miso Ramen", Category = "Japanese", Ingredients = "Ramen noodles, Miso paste, Pork broth, Chashu pork, Soft-boiled egg, Green onions, Corn, Nori", Steps = "1. Prepare pork broth (or use store-bought).\n2. Dissolve miso paste in broth.\n3. Cook ramen noodles separately.\n4. Slice chashu pork.\n5. Assemble bowl: noodles, broth, toppings.\n6. Garnish with nori and green onions.", AverageRating = 4.9, RatingCount = 22 },
        new Recipe { Id = 8, Title = "Teriyaki Salmon", Category = "Japanese", Ingredients = "Salmon fillets, Soy sauce, Mirin, Sugar, Ginger, Sesame seeds, Steamed rice", Steps = "1. Mix soy sauce, mirin, sugar, and ginger.\n2. Marinate salmon for 30 minutes.\n3. Pan-sear salmon skin-side down.\n4. Flip and glaze with marinade.\n5. Cook until glaze caramelizes.\n6. Serve over rice with sesame seeds.", AverageRating = 4.4, RatingCount = 11 },
    };

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            var totalStars = recipe.AverageRating * recipe.RatingCount;
            recipe.RatingCount++;
            recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
        }
    }

    public void Submit(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

