arguments.file_text:
@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>🍳 RecipeShare</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2>Browse by Category</h2>

<div class="row">
    @foreach (var category in Categories)
    {
        <div class="col-md-3 mb-4">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetEmoji(category) @category</h4>
                    <a href="category/@category" class="btn btn-outline-primary mt-2">Browse Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

<div class="mt-4">
    <a href="submit" class="btn btn-success btn-lg">📝 Submit a Recipe</a>
</div>

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }

    private static string GetEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Mexican" => "🇲🇽",
        "Japanese" => "🇯🇵",
        _ => "🍽️"
    };
}

@page "/category/{CategoryName}"

<PageTitle>@CategoryName Recipes - RecipeShare</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (Recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-muted">
                            @if (recipe.RatingCount > 0)
                            {
                                <span>⭐ @recipe.AverageRating (@recipe.RatingCount ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-outline-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<RecipeShare.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnInitialized()
    {
        Recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"

<PageTitle>@(Recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (Recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@Recipe.Title</h1>
    <p class="text-muted">Category: @Recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.')
                text = text[3..];
            <li>@text</li>
        }
    </ol>

    <h3>Rating</h3>
    @if (Recipe.RatingCount > 0)
    {
        <p>⭐ @Recipe.AverageRating / 5 (@Recipe.RatingCount ratings)</p>
    }
    else
    {
        <p>No ratings yet. Be the first!</p>
    }

    <StarRating RecipeId="Recipe.Id" @rendermode="InteractiveServer" />

    <a href="category/@Recipe.Category" class="btn btn-outline-secondary mt-3">← Back to @Recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer

<div class="star-rating mt-2 mb-3">
    @if (!HasRated)
    {
        <p>Rate this recipe:</p>
        <div>
            @for (int i = 1; i <= 5; i++)
            {
                var star = i;
                <button class="btn btn-link fs-4 p-0 me-1" @onclick="() => SubmitRating(star)"
                        title="@star star(s)">
                    @(star <= HoverStar ? "⭐" : "☆")
                </button>
            }
        </div>
    }
    else
    {
        <p class="text-success">✓ You rated this recipe @SelectedRating star(s). Thank you!</p>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private int HoverStar { get; set; }
    private int SelectedRating { get; set; }
    private bool HasRated { get; set; }

    private void SubmitRating(int stars)
    {
        RecipeService.AddRating(RecipeId, stars);
        SelectedRating = stars;
        HasRated = true;
    }
}

@page "/submit"
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>📝 Submit a Recipe</h1>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4>Recipe submitted successfully!</h4>
        <p>Your recipe "<strong>@Model.Title</strong>" has been added to the @Model.Category category.</p>
        <a href="/" class="btn btn-primary">Back to Home</a>
    </div>
}
else
{
    <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" @bind-Value="Model.Title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" @bind-Value="Model.Category" class="form-select">
                <option value="">-- Select a category --</option>
                <option value="Italian">Italian</option>
                <option value="Indian">Indian</option>
                <option value="Mexican">Mexican</option>
                <option value="Japanese">Japanese</option>
                <option value="American">American</option>
                <option value="French">French</option>
                <option value="Other">Other</option>
            </InputSelect>
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients</label>
            <InputTextArea id="ingredients" @bind-Value="Model.Ingredients" class="form-control" rows="5"
                           placeholder="One ingredient per line or comma-separated" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps</label>
            <InputTextArea id="steps" @bind-Value="Model.Steps" class="form-control" rows="6"
                           placeholder="Describe each step on a new line" />
        </div>

        <button type="submit" class="btn btn-success"
                disabled="@(string.IsNullOrWhiteSpace(Model.Title) || string.IsNullOrWhiteSpace(Model.Category))">
            Submit Recipe
        </button>
        <a href="/" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private RecipeShare.Models.RecipeSubmission Model { get; set; } = new();
    private bool Submitted { get; set; }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Model.Title) || string.IsNullOrWhiteSpace(Model.Category))
            return;

        RecipeService.Submit(Model);
        Submitted = true;
    }
}

